import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int maxLength = Math.min(input.length(), 10); // Limiting input length to 10 characters
        char[] buffer = new char[maxLength];

        input.getChars(0, maxLength, buffer, 0); // Copy up to maxLength characters

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

